mapper.select:
SELECT id, notice_title AS noticeTitle, notice_type AS noticeType, notice_content AS noticeContent,
       recipient_id AS recipientId, read_status AS readStatus, send_time AS sendTime
FROM sys_notice

    deleted = 0
    AND recipient_id = #{recipientId}

        AND notice_type = #{query.noticeType}


        AND read_status = #{query.readStatus}


        AND notice_title LIKE CONCAT('%', #{query.keyword}, '%')


ORDER BY send_time DESC, id DESC
